sql:
SELECT authors.author_name, resources.resource_id
FROM resources
INNER JOIN authors ON resources.author_id = authors.author_id;

external_knowledge:
- Mapping refers to resources tagged with tags starting with "map".;
- Stats refer to the total number of resources created and the average rating received.; 
- Prolific refers to having a high number of resources created.; 
- Quality of ratings refers to the average rating value of their resources.;

sql:
SELECT resource_id, view_count
FROM resources
WHERE view_count > (SELECT AVG(view_count) FROM resources);

SELECT title
FROM resources
WHERE view_count > 5;

SELECT r.resource_id, r.title, r.view_count, (
    SELECT AVG(view_count) 
    FROM resources
) AS average_view_count
FROM resources r
WHERE r.view_count > (
    SELECT AVG(view_count) 
    FROM resources
);
